import React from "react";
import styled from "styled-components";

function Jumbotron() {
  return (
    <Container>
      <Nav>
        <img src="https://i.ibb.co/r5krrdz/logo.png" alt="" />
        <NavButton>Home</NavButton>
      </Nav>
      <Content>
        <h1>
          Unlimited movies, TV <br /> shows, and more.
        </h1>
        <h4>Watch anywhere. Cancel anytime.</h4>
        <p>
          Ready to watch? Enter your email to create or restart your membership.
        </p>
        <Input>
          <input
            type="text"
            placeholder="Email address
"
          />
          <span>Get Started</span>
        </Input>
      </Content>
    </Container>
  );
}

export default Jumbotron;

const Container = styled.div`
  width: 100%;
  height: 100vh;
  position: relative;
  background: url("/images/misc/home-bg.jpg");
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;

  &:before {
    content: "";
    position: absolute;
    width: 100%;
    height: 100%;
    top: 0;
    left: 0;
    background: rgba(0, 0, 0, 0.3);
  }
`;

const Nav = styled.nav`
  position: absolute;
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  padding: 2% 5%;
  img {
    width: 180px;
    height: 40px;
  }
`;

const NavButton = styled.button`
  background-color: #e50914;

  padding: 7px 17px;
  font-weight: 400;
  font-size: 18px;
  color: #fff;
  border: 0;
  outline: 0;
  border-radius: 6px;
  cursor: pointer;
`;

const Content = styled.div`
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: #fff;

  h1 {
    font-size: 70px;
    margin-bottom: 10px;
  }

  h4 {
    text-align: center;
    font-size: 25px;
    margin-bottom: 15px;
  }

  p {
    text-align: center;
    font-size: 20px;
    margin-bottom: 30px;
  }
`;

const Input = styled.div`
  display: flex;
  align-items: center;

  input {
    flex: 1;
    padding: 20px;
    border: 0;
    outline: 0;
    position: relative;
  }

  span {
    background-color: #e50914;
    padding: 19px;
    max-height: fit-content;
    position: absolute;
    right: 0;
    display: block;
    font-size: 20px;
  }
`;
